"use client";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { FaFilePdf } from "react-icons/fa6";
import { MdOutlineFileDownload } from "react-icons/md";
import { FaEye } from "react-icons/fa";
interface OfferLetter {
  name: string;
  url: string;
}

export default function Dashboard() {
  const [offerLetters, setOfferLetters] = useState<OfferLetter[]>([]);
  const [documents, setDocuments] = useState<OfferLetter[]>([]);
  const router = useRouter();

  useEffect(() => {
    const fetchOfferLetters = async () => {
      try {
        const response = await fetch("/api/offer-letter");
        const data = await response.json();
        if (data.offerLetters) {
          setOfferLetters(data.offerLetters);
        }
      } catch (error) {
        console.error("Error fetching offer letters:", error);
      }
    };

    const fetchDocuments = async () => {
      try {
        const response = await fetch("/api/send-documents");
        const data = await response.json();
        console.log("Documents : ",data);
        
        if (data.documents) {
          setDocuments(data.documents);
        }
      } catch (error) {
        console.error("Error fetching documents:", error);
      }
    }
    fetchDocuments();

      fetchOfferLetters();
  }, []);

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold mb-6">Dashboard</h1>
      <h4 className="text-2xl font-semibold mb-4 pt-5">Offer Letters</h4>

      {offerLetters.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {offerLetters.map((file, index) => (
            <div key={index} className="bg-white shadow-lg rounded-lg p-4 w-75">
              <div className="d-flex align-items-center justify-content-center py-5">
                <FaFilePdf size={50} />
              </div>
              <h5 className="text-lg font-semibold truncate">{file.name}</h5>
              <div className="flex justify-between mt-4">
                <a
                  href={file.url}
                  target="_blank"
                  className="hover:underline text-black text-decoration-none"
                >
                  <FaEye size={30} />
                </a>
                <a
                  href={file.url}
                  download={file.name}
                  className=" hover:underline text-black text-decoration-none"
                >
                  <MdOutlineFileDownload size={30} />
                </a>
                <button
                  onClick={() => router.push("/payment")}
                  className="text-red-500 hover:underline"
                >
                  Payment
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-gray-500 text-center mt-10">
          Your Offer Letters will be displayed here in minutes...
        </div>
      )}

      <h4 className="text-2xl font-semibold mb-4 pt-5"> Your Documents</h4>

      {
        documents.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {documents.map((file, index) => (
              <div key={index} className="bg-white shadow-lg rounded-lg p-4 w-75">
                <div className="d-flex align-items-center justify-content-center py-5">
                  <FaFilePdf size={50} />
                </div>
                <h5 className="text-lg font-semibold truncate">{file.name}</h5>
                <div className="flex justify-between mt-4">
                  <a
                    href={file.url}
                    target="_blank"
                    className="hover:underline text-black text-decoration-none"
                  >
                    <FaEye size={30} />
                  </a>
                  <a
                    href={file.url}
                    download={file.name}
                    className=" hover:underline text-black text-decoration-none"
                  >
                    <MdOutlineFileDownload size={30} />
                  </a>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-gray-500 text-center mt-10">
            Your Documents will be displayed here...
          </div>
        )
      }

    </div>
  );
}
